class Solution:
    def calculateScore(self, s):
        n = len(s)
        marked = [False] * n
        score = 0
        for i in range(n):
            if marked[i]:
                continue
            mirror = chr(ord('a') + ord('z') - ord(s[i]))
            j = i - 1
            found = -1
            while j >= 0:
                if not marked[j] and s[j] == mirror:
                    found = j
                    break
                j -= 1
            if found != -1:
                marked[i] = True
                marked[found] = True
                score += i - found
        return score

