var calculateScore = function(s) {
    const stacks = Array.from({ length: 26 }, () => []);
    let score = 0;
    for (let i = 0; i < s.length; i++) {
        const c = s.charCodeAt(i) - 97;
        const m = 25 - c;
        if (stacks[m].length) {
            const j = stacks[m].pop();
            score += i - j;
        } else {
            stacks[c].push(i);
        }
    }
    return score;
};
